        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the discriminator property from "Discriminator" to "$type".
            // Preserve the old property name for compatibility with existing 500K documents.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "EntityName|<key>" to just "<key>".
            // Preserve the old format so existing documents remain addressable.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id");
            entity.UseIdPrefix();
        });
    }
