using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE #1: EF Core 9 renamed the discriminator JSON property
            // from "Discriminator" to "$type". Existing 500K documents use "Discriminator".
            // Preserve the old name so queries and existing data continue to work.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE #2: EF Core 9 changed the id format from "Product|123"
            // to just "123". Existing documents use the old format.
            // Map an explicit CosmosId property that preserves the "TypeName|Key" format.
            entity.Property(p => p.CosmosId).ToJsonProperty("id");
            entity.HasPartitionKey(p => p.CosmosId);
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = default!;

    // Preserves the EF Core 8 id format: "Product|<key>"
    public string CosmosId
    {
        get => $"Product|{Id}";
        private set { }
    }
}

